  "S34": ["𓋹", "U+132F9", "ankh, life, hope"],
  "L1": ["𓆣", "U+131A3", "scarab, new start, luck"],
  "M1+Z1": ["𓇋𓏏", "U+131CB+U+133CF", "reed leaves, spirit in nature"],
  "F34": ["𓄹", "U+13139", "heart as flesh, love, fear"],
  "F27": [">𓃒", "U+130D2", "hide and tail, animal essence, instinctual emotion"],
  "A14": ["𓃀", "U+130C0", "tears, sadness, crying"],
  "M1": ["𓇋", "U+131CB", "reed, food, growth"],
  "O1": ["𓉐", "U+13250", "house, shelter, stability"],
  "X1": ["𓌃", "U+132C3", "bread, eating"],
  "T30": ["𓈖", "U+13296", "knife, threat, defense"],
  "N5+N5": ["𓇳𓇳", "U+13273+U+13273", "sun twice, seasons"],
  "G1": ["𓄿", "U+1313F", "vulture, aging, mother time"],
