# Function to validate a glyph mapping
@define $validate_glyph = ($gardiner, $glyph, $unicode, $meaning) {
  @validate $glyph_table[$gardiner][0] == $glyph -> "Glyph match: $glyph"
  @validate $glyph_table[$gardiner][1] == $unicode -> "Unicode match: $unicode"
  @validate $glyph_table[$gardiner][2] == $meaning -> "Meaning match: $meaning"
  @output "Validated: $gardiner -> $glyph ($unicode, $meaning)"
}

# Function to process a glyph sequence
@define $process_sequence = ($sequence) {
  @define $result = []
  @for $glyph in $sequence {
    @define $entry = $glyph_table.find($glyph)
    @if $entry {
      @compute $result += "$glyph: $entry[2]"
    } @else {
      @output "Error: Glyph $glyph not found in table. Please define."
    }
  }
  @output "Sequence processed: $result"
}

# Example usage: Validate and process a sequence
@validate_glyph "D2" "𓁶" "U+13076" "face/head, thoughts, identity"
@validate_glyph "N5" "𓇳" "U+13273" "sun, day, warmth, time passing"
@process_sequence ["𓇳", "𓂻", "𓄹"]
